56	        public async Task SelectTest1()
57	        {
58	            var comp = Context.Render<SelectTest1>();
59	            // print the generated html
60	            // select elements needed for the test
61	            var select = comp.FindComponent<MudSelect<string>>();
62	            IElement Menu() => comp.Find("div.mud-popover");
