              {
                  textChangedCount = eventCounter++;
                  text = x;
              })));
            await select.SetParametersAndRenderAsync(parameters => parameters.Add(s => s.SelectedValuesChanged, (Action<IReadOnlyCollection<string>>)(x =>
              {
